sql:
SELECT system_size
FROM solar_systems
WHERE efficiency_rating = (SELECT MAX(efficiency_rating) FROM solar_systems);

SELECT installer_name, contact_email, phone
FROM installers
WHERE certifications LIKE '%NABCEP%';

external_knowledge:
- Top-notch solar systems: implies systems installed by installers with the highest ratings; 
- Best-rated professionals: installers who have received a rating of 5;
- Estimated long-term savings: projected savings over 25 years;
- Potential savings in the long run: average savings over 25 years, sorted in descending order.

sql:
SELECT client_id, installer_id, rating, review
FROM installer_ratings
WHERE rating >= 4;

SELECT COUNT(*) as num_systems, AVG(cost_per_watt) as avg_cost
FROM solar_systems
WHERE system_size > '5 kW';

SELECT clients.client_name, feedback.comments
FROM clients
JOIN feedback ON clients.client_id = feedback.client_id;

SELECT system_size, cost_per_watt
FROM solar_systems
WHERE efficiency_rating > 85;

external_knowledge:
'satisfied customers' in this context refers to clients who have given the highest rating of 5;
'top rating' corresponds to the maximum rating of 5 on the scale;
'the installer company' specifically refers to the company named 'Solar Installations'.

sql:
SELECT clients.client_name 
FROM clients 
JOIN quotes ON clients.client_id = quotes.client_id;

SELECT incentive_name, description, amount
FROM incentives
WHERE amount = (
    SELECT MAX(amount) FROM incentives
);
